query MetaobjectDefinitionRecreateRead(
  $oldDefinitionId: ID!
  $newDefinitionId: ID!
  $type: String!
  $oldEntryId: ID!
  $oldHandle: MetaobjectHandleInput!
  $newFirstId: ID!
  $newSecondId: ID!
  $newFirstHandle: MetaobjectHandleInput!
  $newSecondHandle: MetaobjectHandleInput!
) {
  oldDefinition: metaobjectDefinition(id: $oldDefinitionId) {
    ...MetaobjectDefinitionRecreateDefinitionFields
  }
  newDefinition: metaobjectDefinition(id: $newDefinitionId) {
    ...MetaobjectDefinitionRecreateDefinitionFields
  }
  byType: metaobjectDefinitionByType(type: $type) {
    ...MetaobjectDefinitionRecreateDefinitionFields
  }
  oldEntry: metaobject(id: $oldEntryId) {
    ...MetaobjectDefinitionRecreateReadEntryFields
  }
  oldEntryByHandle: metaobjectByHandle(handle: $oldHandle) {
    ...MetaobjectDefinitionRecreateReadEntryFields
  }
  newFirst: metaobject(id: $newFirstId) {
    ...MetaobjectDefinitionRecreateReadEntryFields
  }
  newSecond: metaobject(id: $newSecondId) {
    ...MetaobjectDefinitionRecreateReadEntryFields
  }
  newFirstByHandle: metaobjectByHandle(handle: $newFirstHandle) {
    ...MetaobjectDefinitionRecreateReadEntryFields
  }
  newSecondByHandle: metaobjectByHandle(handle: $newSecondHandle) {
    ...MetaobjectDefinitionRecreateReadEntryFields
  }
  catalog: metaobjects(type: $type, first: 10, sortKey: "display_name") {
    edges {
      cursor
      node {
        ...MetaobjectDefinitionRecreateReadEntryFields
      }
    }
    nodes {
      ...MetaobjectDefinitionRecreateReadEntryFields
    }
    pageInfo {
      hasNextPage
      hasPreviousPage
      startCursor
      endCursor
    }
  }
}

